static func updateFlag<Value: Equatable>(
  key: InputKey, value: Value, origin: InputOrigin,
  values: inout ParsedValues, exclusivity: FlagExclusivity
) throws {
  let hasUpdated: Bool
  if let previous = values.element(forKey: key) {
    hasUpdated = !previous.inputOrigin.elements.isEmpty
  } else {
    hasUpdated = false
  }

  switch (hasUpdated, exclusivity.base) {
  case (true, .exclusive):
    // This value has already been set.
    if let previous = values.element(forKey: key) {
      if (previous.value as? Value) == value {
        // setting the value again will consume the argument
        values.set(value, forKey: key, inputOrigin: origin)
      } else {
        throw ParserError.duplicateExclusiveValues(
          previous: previous.inputOrigin, duplicate: origin,
          originalInput: values.originalInput)
      }
    }
  case (true, .chooseFirst):
    values.update(
      forKey: key, inputOrigin: origin, initial: value, closure: { _ in })
  case (false, _), (_, .chooseLast):
    values.set(value, forKey: key, inputOrigin: origin)
  }
}

@inlinable
  internal mutating func merge(
  _ level: _HashLevel,
  _ other: _HashNode,
  _ combine: (Value, Value) throws -> Value
  ) rethrows -> Int {
    guard other.count > 0 else { return 0 }
    guard self.count > 0 else {
      self = other
      return self.count
    }
    if level.isAtRoot, self.hasSingletonItem {
      // In this special case, the root node may turn into a collision node
      // during the merge process. Prevent this from causing issues below by
      // handling it up front.
      var copy = other
      let delta = try self.read { l in
        let lp = l.itemPtr(at: .zero)
        let c = copy.count
        let res = copy.updateValue(
          level, forKey: lp.pointee.key, _Hash(lp.pointee.key)
        ) {
          $0.initialize(to: lp.pointee)
        }
        if !res.inserted {
          try UnsafeHandle.update(res.leaf) {
            let p = $0.itemPtr(at: res.slot)
            p.pointee.value = try combine(lp.pointee.value, p.pointee.value)
          }
        }
        return c - (res.inserted ? 0 : 1)
      }
      self = copy
      return delta
    }

    return try _merge(level, other, combine)
  }

@inlinable
    @inline(__always)
    internal func copy() -> Storage {
      let capacity = self.header.capacity
      let count = self.header.count
      let subtreeCount = self.header.subtreeCount
      let depth = self.header.depth
      let isLeaf = self.header.children == nil

      let newStorage = Storage.create(withCapacity: capacity, isLeaf: isLeaf)

      newStorage.header.count = count
      newStorage.header.subtreeCount = subtreeCount
      newStorage.header.depth = depth

      self.withUnsafeMutablePointerToElements { oldKeys in
        newStorage.withUnsafeMutablePointerToElements { newKeys in
          newKeys.initialize(from: oldKeys, count: count)
        }
      }

      if _Node.hasValues {
        newStorage.header.values.unsafelyUnwrapped
          .initialize(
            from: self.header.values.unsafelyUnwrapped,
            count: count
          )
      }

      newStorage.header.children?
        .initialize(
          from: self.header.children.unsafelyUnwrapped,
          count: count + 1
        )

      return newStorage
    }

@inlinable
  public init(from decoder: Decoder) throws {
    // We expect to be encoded as an array of alternating key-value pairs.
    var container = try decoder.unkeyedContainer()
    var builder = _Tree.Builder(deduplicating: true)
    var previousKey: Key? = nil

    while !container.isAtEnd {
      let key = try container.decode(Key.self)

      guard !container.isAtEnd else {
        throw DecodingError.dataCorrupted(
          DecodingError.Context(
            codingPath: container.codingPath,
            debugDescription: "Unkeyed container reached end before value in key-value pair"
          )
        )
      }

      let value = try container.decode(Value.self)

      guard previousKey == nil || previousKey! < key else {
        let context = DecodingError.Context(
          codingPath: container.codingPath,
          debugDescription: "Decoded elements out of order.")
        throw DecodingError.dataCorrupted(context)
      }

      builder.append((key, value))
      previousKey = key
    }

    self.init(_rootedAt: builder.finish())
  }

@_spi(Testing)
    public static func dup(error: Error, path: FilePath, location: SourceLocation) -> Self {
        let code: FileSystemError.Code
        let message: String
        let cause: Error

        if let errno = error as? Errno {
            switch errno {
            case .badFileDescriptor:
                code = .closed
                message = "Unable to duplicate descriptor of closed handle for '\(path)'."
            default:
                code = .unknown
                message = "Unable to duplicate descriptor of handle for '\(path)'."
            }
            cause = SystemCallError(systemCall: "dup", errno: errno)
        } else {
            code = .unknown
            message = "Unable to duplicate descriptor of handle for '\(path)'."
            cause = error
        }

        return FileSystemError(
            code: code,
            message: message,
            cause: cause,
            location: location
        )
    }

private func _addHTTPClientHandlersFallback(
    position: ChannelPipeline.SynchronousOperations.Position,
    leftOverBytesStrategy: RemoveAfterUpgradeStrategy,
    enableOutboundHeaderValidation: Bool,
    encoderConfiguration: HTTPRequestEncoder.Configuration,
    decoderLimitConfiguration: NIOHTTPDecoderLimitConfiguration,
    withClientUpgrade upgrade: NIOHTTPClientUpgradeConfiguration?
) throws {
    self.eventLoop.assertInEventLoop()
    let requestEncoder = HTTPRequestEncoder(configuration: encoderConfiguration)
    let responseDecoder = HTTPResponseDecoder(
        leftOverBytesStrategy: leftOverBytesStrategy,
        limitConfiguration: decoderLimitConfiguration
    )
    var handlers: [RemovableChannelHandler] = [requestEncoder, ByteToMessageHandler(responseDecoder)]

    if enableOutboundHeaderValidation {
        handlers.append(NIOHTTPRequestHeadersValidator())
    }

    if let upgrade = upgrade {
        let upgrader = NIOHTTPClientUpgradeHandler(
            upgraders: upgrade.upgraders,
            httpHandlers: handlers,
            upgradeCompletionHandler: upgrade.completionHandler
        )
        handlers.append(upgrader)
    }

    try self.addHandlers(handlers, position: position)
}

static func create(iovectorCount: Int) -> Self {
    let head = PooledBufferHead(iovectorCount: iovectorCount)

    let baseStorage = Self.create(minimumCapacity: head.totalByteCount) { _ in
        head
    }

    // Here we set up our memory bindings.

    // Intentionally using a force cast here to avoid a miss compiliation in 5.10.
    // This is as fast as an unsafeDownCast since ManagedBuffer is inlined and the optimizer
    // can eliminate the upcast/downcast pair
    let storage = baseStorage as! Self
    storage.withUnsafeMutablePointers { headPointer, tailPointer in
        UnsafeRawPointer(tailPointer + headPointer.pointee.iovectorOffset).bindMemory(
            to: IOVector.self,
            capacity: iovectorCount
        )
        UnsafeRawPointer(tailPointer + headPointer.pointee.bufferOwnersOffset).bindMemory(
            to: Unmanaged<AnyObject>.self,
            capacity: iovectorCount
        )
        UnsafeRawPointer(tailPointer + headPointer.pointee.memorySentinelOffset).bindMemory(
            to: MemorySentinel.self,
            capacity: 1
        )
    }

    return storage
}

static func create(count: Int) -> Self {
    let head = PooledMsgBufferHead(count: count)

    let baseStorage = Self.create(minimumCapacity: head.totalByteCount) { _ in
        head
    }

    // Intentionally using a force cast here to avoid a miss compiliation in 5.10.
    // This is as fast as an unsafeDownCast since ManagedBuffer is inlined and the optimizer
    // can eliminate the upcast/downcast pair
    let storage = baseStorage as! Self
    storage.withUnsafeMutablePointers { headPointer, tailPointer in
        UnsafeRawPointer(tailPointer + headPointer.pointee.msgHdrsOffset).bindMemory(
            to: MMsgHdr.self,
            capacity: count
        )
        UnsafeRawPointer(tailPointer + headPointer.pointee.addressesOffset).bindMemory(
            to: sockaddr_storage.self,
            capacity: count
        )
        // space for control message data not needed to be bound
        UnsafeRawPointer(tailPointer + headPointer.pointee.memorySentinelOffset).bindMemory(
            to: MemorySentinel.self,
            capacity: 1
        )
    }

    return storage
}

@inlinable
    mutating func userFutureCompleted(with result: Result<NegotiationResult, Error>) -> UserFutureCompletedAction? {
        switch self.state {
        case .initial:
            preconditionFailure("Invalid state \(self.state)")

        case .waitingForUser(let buffer):

            switch result {
            case .success(let value):
                if !buffer.isEmpty {
                    self.state = .unbuffering(buffer: buffer)
                    return .startUnbuffering(value)
                } else {
                    self.state = .finished
                    return .removeHandler(value)
                }

            case .failure(let error):
                if !buffer.isEmpty {
                    self.state = .unbuffering(buffer: buffer)
                    return .fireErrorCaughtAndStartUnbuffering(error)
                } else {
                    self.state = .finished
                    return .fireErrorCaughtAndRemoveHandler(error)
                }
            }

        case .unbuffering:
            preconditionFailure("Invalid state \(self.state)")

        case .finished:
            // It might be that the user closed the channel in his closure. We have to tolerate this.
            return .none
        }
    }
